const GRID_SIZE = 30;
const GRID_WIDTH = 360;
const WIN_Y = -240;
const RIVER_START = -115;
const RIVER_END = -45;
const CAR_ROWS = [100, 50, 0];
const CAR_WIDTH = 40;
const CAR_HEIGHT = 15;
const ROAD_WIDTH = 70;

// Initialize score tracking
if (!state.maxY) {
  state.maxY = self.y;
  state.gameOver = false;
}

// Check win condition
if (self.y <= WIN_Y && !state.gameOver) {
  state.maxY = Math.max(state.maxY, self.y);
  state.score = Math.floor((250 - state.maxY) / GRID_SIZE);
  // Reset to start
  self.setPosition(0, 250);
  state.maxY = 250;
}

// Handle input (arrow keys move on grid)
const oldX = self.x;
const oldY = self.y;

if (Input.isKeyPressed("ArrowUp")) {
  self.y -= GRID_SIZE;
}
if (Input.isKeyPressed("ArrowDown")) {
  self.y += GRID_SIZE;
}
if (Input.isKeyPressed("ArrowLeft")) {
  self.x -= GRID_SIZE;
}
if (Input.isKeyPressed("ArrowRight")) {
  self.x += GRID_SIZE;
}

// Wrap horizontally
if (self.x < -GRID_WIDTH / 2) self.x = GRID_WIDTH / 2;
if (self.x > GRID_WIDTH / 2) self.x = -GRID_WIDTH / 2;

// Boundary check vertical
if (self.y > 270) self.y = 270;
if (self.y < -280) self.y = -280;

// Track highest y reached for score
if (self.y < state.maxY) {
  state.maxY = self.y;
  state.score = Math.floor((250 - state.maxY) / GRID_SIZE);
}

// Check collision with cars
const cars = [
  'Car1_R1', 'Car2_R1', 'Car3_R1',
  'Car1_R2', 'Car2_R2', 'Car3_R2',
  'Car1_R3', 'Car2_R3', 'Car3_R3'
];

let hit = false;
for (let carName of cars) {
  const car = entities.get(carName);
  if (car) {
    const dx = Math.abs(self.x - car.x);
    const dy = Math.abs(self.y - car.y);
    if (dx < (20 + CAR_WIDTH) / 2 && dy < (20 + CAR_HEIGHT) / 2) {
      hit = true;
      break;
    }
  }
}

// Check if in river (should be on lily pads - for now, instant loss)
if (self.y > RIVER_START - 20 && self.y < RIVER_END + 20 && !hit) {
  // In river but not on cars - lose
  hit = true;
}

if (hit && !state.gameOver) {
  state.gameOver = true;
  const gameOverText = entities.get('GameOverText');
  if (gameOverText) {
    gameOverText.visible = true;
  }
  // Stay visible but disable movement for a moment
  self.tint = '#ff0000'; // Turn red
}

// Reset with R key
if (Input.isKeyPressed("r") && state.gameOver) {
  state.gameOver = false;
  state.maxY = 250;
  state.score = 0;
  self.setPosition(0, 250);
  self.tint = '#00ff00';
  const gameOverText = entities.get('GameOverText');
  if (gameOverText) {
    gameOverText.visible = false;
  }
}

const SPEED = 80;
const GRID_WIDTH = 360;

self.x += SPEED * dt;

if (self.x > GRID_WIDTH / 2 + 40) {
